/// <reference path="../typings/index.d.ts" />
import jibo = require('jibo');
import {libraries, BeSkill, Options} from '@be/be-framework';
import View = jibo.rendering.gui.views.View;
import CancelTokenSession = libraries.jibo_cai_utils.CancelTokenSession;
import ActionData = jibo.rendering.gui.actions.ActionData;

namespace ViewConfigs {
    export const WAITING_VIEW_CONFIG:string = "resources/views/waiting.json";
    export const SUCCESS_VIEW_CONFIG:string = "resources/views/success.json";
    export const ERRORS_VIEW_CONFIG:string = "resources/views/errors.json";
}

enum RestoreStatus {
    UGC_KEY_TIMEOUT,
    RESTORE_SUCCESS,
    RESTORE_FAILED,
    REFRESH_FAILED,
    CANCELED
}

class Restore extends BeSkill {
    public static Types = {
        BeSkill: BeSkill
    };
s

    private _promiseSession:CancelTokenSession = null;
    private _ugcKeyTimeoutMS:number = 0;
    // the current view rendering
    private _currentView:View = null;
    private _statusCallback:(status:RestoreStatus)=>void = null;

    public get currentView():View {
        return this._currentView;
    }

    /**
     * skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?:Options, ugcKeyTimeoutMS:number=600000/*10 min*/) {
        super(assetPack);

        this._promiseSession = new CancelTokenSession();
        this._ugcKeyTimeoutMS = ugcKeyTimeoutMS;
    }

    public preload(done:(err?:any)=>void):void {
        done();
    }

    /**
     * Start the skill
     * @method open
     */
    public open(result?:any, refresh?:boolean):void;
    public open(result?:any, refresh?:boolean, previousSkillName?:string, previousSkillOptions?:any, callback?:(status:RestoreStatus)=>void):void {
        this.log.info("restore open");

        if(refresh) {
            this.log.warn("refresh called on a restore that should already be in progress");
            callback(RestoreStatus.REFRESH_FAILED);
            return;
        }

        this._isInterruptible = false;

        if(!this._statusCallback && callback) {
            this._statusCallback = callback;
        }

        this._promiseSession.wrap(this._renderScreen(ViewConfigs.WAITING_VIEW_CONFIG))
        .then(()=>{
            this.log.info("Waiting for UGC key");
            this._promiseSession.wrap(this._waitForUGCKey())
            .then(()=>{
                this.log.info("UGC Key is ready. beginning restore");
                jibo.systemManager.restore((error)=>{
                    if(error) {
                        this.log.error("restore returned an error");
                        this._wipeOnRestoreFailed(RestoreStatus.RESTORE_FAILED);
                    }
                    else {
                        this.log.info("restore completed without error");
                        let actionData = new ActionData(ActionData.CALLBACK, { callback: this._successfulRestore.bind(this) });
                        this._promiseSession.wrap(this._renderScreen(ViewConfigs.SUCCESS_VIEW_CONFIG, actionData));
                    }
                });
            })
            .catch((err:Error)=>{
                this.log.error("waiting for UGC Key timed out", err);
                this._wipeOnRestoreFailed(RestoreStatus.UGC_KEY_TIMEOUT);
            });
        });
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    public close(done:() => void):void {
        this.log.info("restore close");
        Promise.resolve()
        .then(()=>{
            return this._promiseSession.cancel()
            .catch((err)=>{
                this.log.error("promise session cancel error", err);
            })
            .then(()=>{
                // whether or not the cancel got a reject from a promise being canceled,
                // we always want to signal that our status has been canceled
                if(this._statusCallback) {
                    this._statusCallback(RestoreStatus.CANCELED);
                    this._statusCallback = null;
                }
            });
        })
        .then(()=>{
            if(this._currentView) {
                return new Promise((resolve)=>{
                    jibo.face.views.removeView(() => {
                        this.log.info("restore waiting view destroyed");
                        resolve();
                    }, jibo.face.views.DOWN, jibo.face.views.DOWN, (err)=>{
                        this.log.error(err);
                        // if the removeView fails don't prevent us from closing the skill
                        resolve();
                    });
                });
            }
        })
        .then(()=>{
            done();
        });
    }

    /**
     * check to see if the UGC key is ready up until a timeout is reached.
     * @method _waitForUGCKey
     */
    private _waitForUGCKey():Promise<void> {
        return new Promise<void>((resolve, reject)=>{
            let itr = null;

            let ugcKeyRetryMethod = function *(){
                let tryAgain = true;

                let startTime = Date.now();
                while(tryAgain) {
                    jibo.secureTransferService.isUGCKeyReady((error:Error, isReady:boolean)=>{
                        // by default we retry the call to check if the ugc key is ready
                        // only if there's an error, if the key is ready, or if we've surpassed our retry time do we not retry
                        if(error) {
                            tryAgain = false;
                            reject(error);
                        }
                        else if(isReady) {
                            tryAgain = false;
                            resolve();
                        }
                        else if(Date.now() - startTime >= this._ugcKeyTimeoutMS){
                            tryAgain = false;
                            reject(new Error("timed out"));
                        }
                        itr.next();
                    });

                    yield tryAgain;
                }
            }.bind(this);
            itr = ugcKeyRetryMethod();
            itr.next();
        });
    }

    /**
     * render a view parameterized by the config
     * @method _renderWaitingScreen
     */
    private _renderScreen(viewConfigPath:string, actionData:ActionData=null):Promise<void> {
        return new Promise<void>((resolve)=>{
            let viewComplete = (view:View)=>{
                this.log.info(`restore view ${viewConfigPath} loaded`);
                this._currentView = view;
                if(actionData) {
                    this._currentView.addAction(actionData, null, false, false, jibo.face.views.TAP);
                }
                resolve();
            };
            let onFailure = (err)=>{
                this._currentView = null;
                // if the changeView fails don't prevent us from continuing with restoring the robot
                this.log.warn(`restore view ${viewConfigPath} failed to load`, err);
                resolve();
            };

            let changeViewOptions = {
                addView: viewConfigPath,
                // removes the previous view before adding the new view
                remove: true
            };

            jibo.face.views.changeView(changeViewOptions, viewComplete, onFailure);
        });
    }

    /**
     * callback hit after a successful restore and the user tapped the screen
     * @method _successfulRestore
     */
    private _successfulRestore():void {
        this.log.info("Restore success");

        jibo.systemManager.reboot((err:Error)=>{
            if(err) {
                this.log.error("Reboot reports failure", err);
            }

            if(this._statusCallback) {
                this._statusCallback(RestoreStatus.RESTORE_SUCCESS);
                this._statusCallback = null;
            }
        });
    }

    /**
     * callback hit after a failed restore and the user tapped the screen
     * @method _failedRestore
     */
    private _failedRestore(status:RestoreStatus):void {
        this.log.info("Restore failed");

        jibo.systemManager.reboot((err:Error)=>{
            if(err) {
                this.log.error("Reboot reports failure", err);
            }

            if(this._statusCallback) {
                this._statusCallback(status);
                this._statusCallback = null;
            }
        });
    }

    /**
     * called after a failed restore to return robot to a wiped state
     * before instructing user to reboot
     * @method _wipeOnRestoreFailed
     */
    private _wipeOnRestoreFailed(status:RestoreStatus):void{
        //verifyConnection may take a minute to fail
        jibo.wifi.verifyConnection(this._promiseSession.wrapCallback((err) => {
            //if verifyConnection failed, tell WipeUtil to skip internet things during wiping
            jibo.utils.WipeUtil.run(this.log, !!err)
            .catch((err)=>{
                this.log.error("unexpected error from wipe util", err);
            })
            .then(()=>{
                let actionData = new ActionData(ActionData.CALLBACK, { callback: ()=>{
                    this._failedRestore(status);
                }});
                this._promiseSession.wrap(this._renderScreen(ViewConfigs.ERRORS_VIEW_CONFIG, actionData));
            });
        }));
    }
}

export = {
    Skill: Restore,
    Restore: Restore,
    ViewConfigs: ViewConfigs,
    RestoreStatus: RestoreStatus
};
